// Generated by Spec-to-RTL pipeline: grammar -> IR -> RTL
// Repair demo setup: injected a register bug that holds its value instead of loading new data when enable is asserted

module register8 (
    input clk,
    input rst_n,
    input en,
    input [7:0] d,
    output reg [7:0] q
);

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            q <= 8'd0;
        end else begin
            if (en) begin
                q <= q;
            end
        end
    end

endmodule
